// 示例组件：显示连接状态
import {useWebSocket, useWebSocketMessage, WebSocketProvider} from "../components/webSocket/WebSocketEnv";
import {useCallback, useState} from "react";

function ConnectionStatus() {
    const {isConnected, error, reconnect} = useWebSocket();

    return (
        <div className="fixed top-4 right-4 z-50">
            <div className={`flex items-center gap-2 px-4 py-2 rounded-lg shadow-lg ${
                isConnected ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'
            }`}>
                <div className={`w-3 h-3 rounded-full ${
                    isConnected ? 'bg-green-500 animate-pulse' : 'bg-red-500'
                }`}></div>
                <span className="text-sm font-medium">
                    {isConnected ? '已连接' : error || '未连接'}
                </span>
                {!isConnected && (
                    <button
                        onClick={reconnect}
                        className="ml-2 text-xs underline hover:no-underline"
                    >
                        重新连接
                    </button>
                )}
            </div>
        </div>
    );
}

// 示例组件：发送消息
function MessageSender() {
    const {sendMessage, isConnected} = useWebSocket();
    const [text, setText] = useState('');

    const handleSend = () => {
        if (text.trim()) {
            sendMessage({text: text.trim()});
            setText('');
        }
    };

    return (
        <div className="p-4 bg-white rounded-lg shadow">
            <h3 className="text-lg font-semibold mb-3">发送消息</h3>
            <div className="flex gap-2">
                <input
                    type="text"
                    value={text}
                    onChange={(e) => setText(e.target.value)}
                    onKeyPress={(e) => e.key === 'Enter' && handleSend()}
                    placeholder="输入消息..."
                    className="flex-1 px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                    disabled={!isConnected}
                />
                <button
                    onClick={handleSend}
                    disabled={!isConnected || !text.trim()}
                    className="px-4 py-2 bg-blue-500 text-white rounded-lg hover:bg-blue-600 disabled:bg-gray-300 disabled:cursor-not-allowed"
                >
                    发送
                </button>
            </div>
        </div>
    );
}

// 示例组件：消息列表
function MessageList() {
    const [messages, setMessages] = useState([]);

    useWebSocketMessage(useCallback((data) => {
        setMessages(prev => [...prev, {
            id: Date.now(),
            data,
            timestamp: new Date().toLocaleTimeString()
        }]);
    }, []));

    return (
        <div className="p-4 bg-white rounded-lg shadow">
            <h3 className="text-lg font-semibold mb-3">收到的消息</h3>
            <div className="space-y-2 max-h-96 overflow-y-auto">
                {messages.length === 0 ? (
                    <p className="text-gray-500 text-sm">暂无消息</p>
                ) : (
                    messages.map((msg) => (
                        <div key={msg.id} className="p-3 bg-gray-50 rounded border border-gray-200">
                            <div className="text-xs text-gray-500 mb-1">{msg.timestamp}</div>
                            <pre className="text-sm overflow-x-auto">
                                {JSON.stringify(msg.data, null, 2)}
                            </pre>
                        </div>
                    ))
                )}
            </div>
        </div>
    );
}

// 主应用组件
function Testpage2() {
    return (
        <WebSocketProvider url="ws://localhost:8765">
            <div className="min-h-screen bg-gray-100 p-8">
                <ConnectionStatus/>

                <div className="max-w-4xl mx-auto">
                    <h1 className="text-3xl font-bold text-gray-800 mb-8">
                        WebSocket 通信演示
                    </h1>

                    <div className="grid gap-6">
                        <MessageSender/>
                        <MessageList/>
                    </div>
                </div>
            </div>
        </WebSocketProvider>
    );
}

export default Testpage2
